package com.qinet.feastique.serviceimport com.qinet.feastique.exception.DuplicateFoundExceptionimport com.qinet.feastique.exception.PermissionDeniedExceptionimport com.qinet.feastique.exception.RequestedEntityNotFoundExceptionimport com.qinet.feastique.exception.UserNotFoundExceptionimport com.qinet.feastique.model.dto.FoodDtoimport com.qinet.feastique.model.entity.Menuimport com.qinet.feastique.model.entity.provisions.addOn.FoodAddOnimport com.qinet.feastique.model.entity.provisions.complement.FoodComplementimport com.qinet.feastique.model.entity.discount.FoodDiscountimport com.qinet.feastique.model.entity.provisions.food.Foodimport com.qinet.feastique.model.entity.provisions.food.FoodAvailabilityimport com.qinet.feastique.model.entity.provisions.food.FoodImageimport com.qinet.feastique.model.entity.provisions.food.FoodOrderTypeimport com.qinet.feastique.model.entity.provisions.food.FoodSizeimport com.qinet.feastique.model.enums.Dayimport com.qinet.feastique.model.enums.OrderTypeimport com.qinet.feastique.repository.MenuRepositoryimport com.qinet.feastique.repository.addOn.AddOnRepositoryimport com.qinet.feastique.repository.complement.ComplementRepositoryimport com.qinet.feastique.repository.discount.DiscountRepositoryimport com.qinet.feastique.repository.food.FoodRepositoryimport com.qinet.feastique.repository.vendor.VendorRepositoryimport com.qinet.feastique.security.UserSecurityimport com.qinet.feastique.utility.DuplicateUtilityimport org.springframework.stereotype.Serviceimport org.springframework.transaction.annotation.Transactionalimport java.util.*import kotlin.jvm.optionals.getOrElse@Serviceclass FoodService(    private val foodRepository: FoodRepository,    private val vendorRepository: VendorRepository,    private val complementRepository: ComplementRepository,    private val addOnRepository: AddOnRepository,    private val discountRepository: DiscountRepository,    private val menuRepository: MenuRepository,    private val duplicateUtility: DuplicateUtility) {    @Transactional(readOnly = true)    fun getFoodById(id: UUID, vendorDetails: UserSecurity): Food {        val food = foodRepository.findById(id)            .orElseThrow { RequestedEntityNotFoundException("No food found for id: $id") }            .also {                if (it.vendor.id != vendorDetails.id) {                    throw PermissionDeniedException("You do not have permission to access discount.")                }            }        return food    }    @Transactional(readOnly = true)    fun getAllFoods(vendorDetails: UserSecurity): List<Food> {        val foods = foodRepository.findAllByVendorId(vendorDetails.id)            .takeIf { it.isNotEmpty() }            ?: throw RequestedEntityNotFoundException("No food found for the vendor: ${vendorDetails.id}")        foods.also { list ->            if (list.any { it.vendor.id != vendorDetails.id }) {                throw PermissionDeniedException("You do not have the permission to access these foods.")            }        }        return foods    }    @Transactional    fun deleteFood(id: UUID, vendorDetails: UserSecurity) {        val food = getFoodById(id, vendorDetails)        foodRepository.delete(food)    }    @Transactional    fun saveFood(food: Food): Food {        return foodRepository.save(food)    }    @Transactional    fun addOrUpdateFood(foodDto: FoodDto, vendorDetails: UserSecurity): Food {        val vendor = vendorRepository.findById(vendorDetails.id)            .orElseThrow { UserNotFoundException("Vendor not found.") }        // Information meant for the food table        // Determine if food is to be created or update an existing one        var food: Food = if (foodDto.id != null) {            foodRepository.findById(foodDto.id!!)                .orElseThrow { RequestedEntityNotFoundException("Food not found.") }                .also {                    if (it.vendor.id != vendorDetails.id) {                        throw PermissionDeniedException("You do not have permission to update food ${it.name}")                    }                }        } else {            Food().apply {                this.vendor = vendor            }        }        if (foodDto.id == null) {            // Check if the vendor has already added food with the same name            if (!duplicateUtility.isDuplicateFoodFound(foodDto.foodName!!, vendorDetails.id)) {                food.name = foodDto.foodName ?: throw IllegalArgumentException("Please enter a food name.")                val nextNumber = foodRepository.count() + 1                food.foodNumber = "FD-${String.format("%06d", nextNumber)}"            } else {                throw DuplicateFoundException("A food with the name: ${foodDto.foodName} already exist. Cannot add duplicate.")            }        } else {            food.name = requireNotNull(foodDto.foodName) { "Please enter a food name." }        }        food.mainCourse = requireNotNull(foodDto.mainCourse) { "Please enter a main course." }        food.description = requireNotNull(foodDto.description) { "Please enter a description." }        food.price = requireNotNull(foodDto.basePrice) { "Please enter a base price." }        food.preparationTime = requireNotNull(foodDto.preparationTime) { "Please enter a preparation time." }        food.deliveryTime = foodDto.deliveryTime        food.deliveryFee = foodDto.deliveryFee        food = saveFood(food)        // Remove old relationships when updating        if (foodDto.id != null) {            food.foodComplement.clear()            food.foodSize.clear()            food.foodAddOn.clear()            food.foodOrderType.clear()            food.foodImage.clear()            food.foodAvailability.clear()        }        // Information meant for the food_image table        val foodImages = foodDto.foodImage.map {            FoodImage().apply {                this.imageUrl = it                this.food = food            }        }        food.foodImage.addAll(foodImages)        // Information meant for the food_complement table        val complements = complementRepository.findAllByIdInAndVendorId(foodDto.complementIds, vendor.id)            .takeIf { it.isNotEmpty() }            ?: throw RequestedEntityNotFoundException("No complements found for the vendor ${vendor.id}")        require(complements.all {            it.vendor.id == vendorDetails.id        }) {            throw PermissionDeniedException("Vendor: ${vendorDetails.id}) does not have the permission to access these complements.")        }        val foodComplements = complements.map {            FoodComplement().apply {                this.food = food                this.complement = it            }        }        food.foodComplement.addAll(foodComplements)        // Information meant for the discount table        // Get the discounts from the database        val discounts = if (!foodDto.discountIds.isNullOrEmpty()) {            discountRepository.findAllByIdInAndVendorId(foodDto.discountIds!!, vendorDetails.id)        } else {            emptyList()        }        if (discounts.isNotEmpty()) {            require(discounts.all {                it.vendor.id == vendorDetails.id            }) {                throw PermissionDeniedException("Vendor: ${vendorDetails.id}) does not have the permission to access these discounts.")            }        }        if (!discounts.isEmpty()) {            val foodDiscounts =                discounts.map {                    FoodDiscount().apply {                        this.food = food                        this.discount = it                    }                }            food.foodDiscount.addAll(foodDiscounts)        }        // Information meant for the food_size_type table        val foodSizeMap = requireNotNull(foodDto.foodSizeMap) { "FoodSizeMap cannot be null or empty." }        val foodSizeName = (foodDto.foodSizeName)        val foodSizes = if (!foodSizeName.isNullOrEmpty()) {            require (foodSizeMap.size == foodSizeName.size) {                "Mismatch between food size map and names list."            }            foodSizeMap.toList()                .zip(foodSizeName) { (size, priceIncrease), name ->                    FoodSize().apply {                        this.size = size                        this.priceIncrease = priceIncrease                        this.name = name                        this.food = food                    }                }        } else {            foodSizeMap.map { (size, priceIncrease) ->                FoodSize().apply {                    this.size = size                    this.name = size.toString()                    this.priceIncrease = priceIncrease                    this.food = food                }            }        }        food.foodSize.addAll(foodSizes)        // Information meant for the food_order_type table        val foodOrderTypes = foodDto.orderType.map { order ->            FoodOrderType().apply {                this.food = food                this.orderType = OrderType.fromString(order)            }        }        food.foodOrderType.addAll(foodOrderTypes)        // Information meant for the food_add_on table        val addOns = if (!foodDto.addOnIds.isNullOrEmpty()) {            addOnRepository.findAllByIdInAndVendorId(foodDto.addOnIds!!, vendorDetails.id)        } else emptyList()        if (addOns.isNotEmpty()) {            require(addOns.all {                it.vendor.id == vendorDetails.id            }) {                throw PermissionDeniedException("Vendor: ${vendorDetails.id}) does not have the permission to access these add-ons.")            }        }        if (!addOns.isEmpty()) {            val foodAddOns =                addOns.map {                    FoodAddOn().apply {                        this.food = food                        this.addOn = it                    }                }            food.foodAddOn.addAll(foodAddOns)        }        // Information meant for the food_availability table        val foodAvailabilities = mutableListOf<FoodAvailability>()        if (foodDto.availability.size > 6 || foodDto.availability[0] == Day.EVERYDAY.type) {            foodAvailabilities.add(                FoodAvailability().apply {                    this.food = food                    this.availability = Day.EVERYDAY                }            )        } else if (foodDto.availability[0] == Day.NONE.type) {            foodAvailabilities.add(                FoodAvailability().apply {                    this.food = food                    this.availability = Day.NONE                }            )        } else {            val userSelection = foodDto.availability.map { availability ->                FoodAvailability().apply {                    this.food = food                    this.availability = Day.fromString(availability)                }            }            foodAvailabilities.addAll(userSelection)        }        food.foodAvailability.addAll(foodAvailabilities)        // Updating food with the new references to food complements in the food complement table.        food = saveFood(food)        // Information meant for the  menu table        // If updating, retrieve        val menu = if (foodDto.id != null) {            menuRepository.findById(food.menu.id)                .getOrElse { throw RequestedEntityNotFoundException("Menu item not found.") }        } else {            Menu().apply {                this.food = food            }        }        for (selection in foodDto.orderType) {            OrderType.fromString(selection)        }        menuRepository.save(menu)        // Reload the saved food with all relationships        val savedFood = foodRepository.findByIdWithAllRelations(food.id)            .orElseThrow { RequestedEntityNotFoundException("Food not found.") }        return savedFood    }}